"""
MKT Christ — Mark chapters 12–13
Output: data/commentary/mkt-christ/mark.json
Run: python3 scripts/zc-christ-mark-12-13.py

Key Christological nodes: the beloved Son in the parable (12:6), the
cornerstone (12:10–11 / Ps 118:22), the Davidic Lord of Ps 110:1 (12:35–37),
the Son of Man coming in clouds (13:26 / Dan 7:13), and the eternal word
(13:31). All 44 + 37 = 81 verses covered.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK_CH12_13 = {
  "12": {
    "1": '<p>A direct revelation: the parable of the vineyard tenants opens with imagery drawn from Isa 5:1–7 — Israel is the vineyard God planted and protected. Christ places himself into this story as the owner\'s son. The parable is a compressed Christological argument: all of Israel\'s prophetic history has been the sending of servants who were rejected; Christ is the final and definitive sending — the beloved son who is killed so that the inheritance might be stolen. The hearers recognize immediately that the parable is about themselves (v.12).</p>',
    "2": '<p>A theme of prophetic continuity: the owner sends servants to collect fruit at harvest time, and the tenants beat them. The parade of rejected servants maps onto Israel\'s rejection of the prophets — a pattern the OT itself laments (Neh 9:26; Jer 7:25–26; 2 Chr 36:15–16). Christ is narrating the entire history of divine patience and human rejection, positioning his own coming as the final chapter of a very long story.</p>',
    "3": '<p>A theme of the prophets\' fate: they took and beat the servant and sent him away empty. The emptied servant anticipates Christ\'s own reception: he will be taken, beaten, and cast out of the city (15:20). The parable is not only a historical retrospective but a passion prediction in narrative form — the fate of all the servants is the fate of the one telling the story.</p>',
    "4": '<p>A theme of escalating rejection: the next servant was struck on the head and treated shamefully. The escalating violence against successive servants mirrors the prophetic tradition\'s witness that persecution of God\'s messengers intensified over time. Christ is the one in whose person all this violence reaches its climax and finds its answer: the resurrection is the vindication of every rejected servant and the vindication of Christ himself as the ultimate rejected one.</p>',
    "5": '<p>A theme of long patience ending: many others were beaten and some killed. The parable\'s catalogue of violence against servants is the ground for the coming judgment (v.9). Christ\'s narration shows that the tenants\' rebellion is not a single act but a sustained pattern — and that the owner\'s patience, though long, has a limit. The judgment on the tenants points forward to 70 CE and to the eschatological judgment that Mark 13 will develop.</p>',
    "6": '<p>A direct revelation: &ldquo;He had one left to send, a son, whom he loved.&rdquo; The language echoes the baptismal voice: &ldquo;you are my beloved Son&rdquo; (1:11; agapētos). Christ is identifying himself as the son in the parable — the final, unique, beloved emissary who supersedes all previous envoys. The Father\'s decision to send the Son as the last resort after all servants have failed is the logic of the incarnation: what no prophet could accomplish, the Son in person will complete — through his death and resurrection.</p>',
    "7": '<p>A revelation of Christ foreseeing his own death: &ldquo;This is the heir. Come, let us kill him, and the inheritance will be ours.&rdquo; The tenants\' reasoning is the logic of every anti-messianic force: if the rightful heir is eliminated, the inheritance can be seized. Christ names the motive behind his approaching passion — it is not misunderstanding but deliberate rejection of his claim. The leaders who will hand him to Pilate have already calculated the advantage of his death.</p>',
    "8": '<p>A revelation of Christ\'s death anticipated in the parable: they killed him and threw him out of the vineyard. The sequence — killed, then cast out — reverses the historical sequence (Jesus was cast out of the city before being killed, 15:20; Heb 13:12) but captures the spiritual reality: the Son is rejected from the very inheritance that belongs to him by right. The ejection from the vineyard is the ejection of the rightful heir — and the one who is cast out becomes the cornerstone (v.10).</p>',
    "9": '<p>A direct revelation of coming judgment: &ldquo;What will the owner of the vineyard do? He will come and destroy the tenants and give the vineyard to others.&rdquo; Christ announces his own coming as Judge. The destruction of the tenants points to the 70 CE judgment on Jerusalem (the vineyard being given to &ldquo;others&rdquo; = the Gentile mission). But the eschatological horizon is even larger: the final judgment when the owner of the vineyard returns in the Son of Man\'s glory (13:26).</p>',
    "10": '<p>A direct citation fulfilled: &ldquo;The stone that the builders rejected has become the cornerstone.&rdquo; The quotation is Ps 118:22, a Hallel psalm sung at Passover. Peter will cite it in Acts 4:11; Paul in Eph 2:20; 1 Pet 2:7 — the early church\'s unanimous identification of Christ as the rejected cornerstone. The one cast out of the vineyard (v.8) is the one the builders reject — and the Father\'s vindication reverses the rejection by making him the foundation of the new building (the church).</p>',
    "11": '<p>A direct citation continued: &ldquo;This is the Lord\'s doing and it is marvelous in our eyes.&rdquo; The Psalm\'s declaration that the cornerstone is the Lord\'s doing (par\' kyriou egeneto haute) names the resurrection as divine action, not human reversal. The marvelousness (thaumastos) is the astonishment of those who see the rejected one vindicated — the same astonishment at the empty tomb (16:5–6). The Hallel psalm that Passover crowds sing is now fulfilled by the Passover death-and-resurrection of the Son.</p>',
    "12": '<p>A revelation of Christ\'s impact on his opponents: they sought to arrest him and feared the crowd, for they perceived that he had told the parable against them; so they left him and went away. The leaders\' perception is correct — Christ has narrated their own coming actions. Their restraint is not respect but political calculation. The same calculation will lead them to arrest him privately at night (14:1–2). Mark shows that the passion is not a surprise but an anticipated collision between Christ\'s claims and the authorities\' self-interest.</p>',
    "13": '<p>A theme of attempted entrapment: they send Pharisees and Herodians to catch Jesus in his words — a politically comprehensive coalition (Torah-strict Pharisees and Rome-friendly Herodians) designed to trap him on the question of Roman taxation. Whatever he answers, one group can charge him. The trap is the political form of the theological rejection: if he cannot be killed for blasphemy, perhaps he can be handed to Rome for sedition. Christ\'s response (v.17) escapes both horns of the dilemma with a single sentence.</p>',
    "14": '<p>A revelation of Christ being approached with false flattery: &ldquo;Teacher, we know that you are true and do not care about anyone\'s opinion.&rdquo; The flattery is accurate in every detail — Jesus is indeed a true teacher who does not defer to human opinion. The irony is that the very quality they praise is the one that makes him impossible to trap: the one who does not care about human opinion will not calibrate his answer to avoid political risk. Their accurate description of him becomes the reason their trap fails.</p>',
    "15": '<p>A revelation of Christ\'s omniscience: knowing their hypocrisy, he said to them, &ldquo;Why are you testing me?&rdquo; The perception of hidden motive is the same faculty that reads the scribes\' unspoken objections (2:8) and the disciples\' silent reasoning (8:17). The divine knowledge of human hearts is exercised quietly throughout Mark — Jesus does not explain how he knows; he simply knows. The testing vocabulary (peirazō) echoes the wilderness temptation (1:13), positioning the Pharisees\' question as a demonic-quality test of the Son.</p>',
    "16": '<p>A theme of Christ and earthly authority: he asks whose image and inscription are on the coin, and they say, &ldquo;Caesar\'s.&rdquo; The denarius with Caesar\'s image and the divine-title inscription (&ldquo;son of the divine Augustus&rdquo;) is the instrument of political economy in Roman Palestine. Christ acknowledges Caesar\'s claim on coins stamped with his image. The deeper point is what bears God\'s image — humanity (Gen 1:27) — and therefore what belongs entirely to God. The coins belong to Caesar; the person belongs to God.</p>',
    "17": '<p>A direct revelation: &ldquo;Give to Caesar what is Caesar\'s and to God what is God\'s.&rdquo; Christ\'s answer is the most elegant division of spheres in all of political theology. But its Christological weight is this: the one who makes the distinction is the one who himself belongs entirely to God and renders to God everything — his obedience, his death, his resurrection. The answer that amazes the questioners is the answer embodied in Christ\'s own life: he is the human being who gives to God precisely what belongs to God, namely everything.</p>',
    "18": '<p>A theme of Christ as revealer of resurrection: Sadducees, who deny the resurrection, come to him. The Sadducean denial of resurrection was based on the absence of explicit resurrection teaching in the Pentateuch. Christ\'s response (vv.24–27) will derive resurrection directly from the Torah — showing that the denial rests on a misreading of texts they themselves accept. Christ is the one who knows the Scriptures because he is the one they are about (John 5:39).</p>',
    "19": '<p>A theme of Christ and Torah: the Sadducees cite Moses\'s levirate marriage legislation (Deut 25:5–6) to construct a reductio ad absurdum against the resurrection. Their argument takes the form of a thought-experiment: if a woman marries seven brothers in succession, whose wife is she at the resurrection? The question assumes resurrection = return to identical earthly conditions. Christ\'s answer (v.25) corrects the assumption before addressing the scriptural argument.</p>',
    "20": '<p>A theme of Christ and the law\'s original purpose: the seven-brothers thought-experiment sets up the Sadducees\' case against resurrection. The elaborate scenario (seven successive husbands, none producing offspring) follows Deut 25:5–6 to its logical extreme. Christ will show that the levirate law\'s purpose (preserving the dead brother\'s name) is itself transcended in the resurrection age — the institution was provisional, not eternal, and the resurrection age operates by different principles entirely.</p>',
    "21": '<p>A theme of Christ addressing the human condition of mortality: the second brother marries her and dies leaving no offspring, and so on through the seventh. The relentless repetition of death in the thought-experiment is itself a picture of the world the resurrection will end — a world where death wins every round. Christ is the one who breaks that cycle not by explaining it away but by dying and rising. The resurrection he is about to teach is the resurrection he will enact.</p>',
    "22": '<p>A theme of the thought-experiment\'s conclusion: last of all the woman also died. The death of the woman after all seven husbands is the ironic endpoint of a scenario meant to mock the resurrection — everyone in it dies. Christ\'s answer will turn this into a premise for the resurrection\'s truth: if all die, then God\'s covenant relationship to them (which cannot be severed) requires resurrection.</p>',
    "23": '<p>A theme of the resurrection question Christ will answer: &ldquo;In the resurrection, when they rise again, which one\'s wife will she be?&rdquo; The question assumes that resurrection = reconstitution of earthly social arrangements. Christ\'s answer distinguishes between the present age (marriage for propagation and covenant continuity) and the resurrection age (no marriage, because death and the need for propagation no longer exist). The Sadducees have read the future through the lens of the present — a hermeneutical error that misses the transformation the resurrection brings.</p>',
    "24": '<p>A direct revelation: &ldquo;Is this not the reason you are wrong, because you know neither the Scriptures nor the power of God?&rdquo; Christ names the double error: ignorance of what the Scriptures actually teach about God\'s relationship to the living, and ignorance of God\'s power to do what has no precedent in present experience. The same God whose power created the world from nothing can raise the dead. Christ speaks as the one who knows both the Scriptures and the power — he will demonstrate the power in his own resurrection.</p>',
    "25": '<p>A revelation of Christ teaching on resurrection life: &ldquo;When they rise from the dead, they neither marry nor are given in marriage, but are like angels in heaven.&rdquo; The resurrection age is not the restoration of the present age but its transformation. Marriage serves the continuation of life in a mortal world; in the deathless resurrection, that function is transcended. The &ldquo;like angels&rdquo; comparison is not about disembodiment (the resurrection is bodily) but about immortality — angels neither die nor need to reproduce. The resurrection Christ promises is genuine new creation, not resumed mortality.</p>',
    "26": '<p>A direct citation from Torah: &ldquo;Have you not read in the book of Moses, in the passage about the burning bush, how God spoke to him, saying, I am the God of Abraham and the God of Isaac and the God of Jacob?&rdquo; The quotation is Exod 3:6, from the portion of Torah the Sadducees accepted. The Christological move is to read the present tense: God does not say &ldquo;I was the God of Abraham&rdquo; but &ldquo;I am&rdquo; — implying that the relationship is ongoing. The dead patriarchs are still in living relationship with God; therefore death has not ended their existence.</p>',
    "27": '<p>A direct revelation: &ldquo;He is not God of the dead, but of the God of the living. You are quite wrong.&rdquo; Christ derives the resurrection from the character of God: a God who sustains covenant relationship cannot have a relationship with the non-existent. Abraham, Isaac, and Jacob are alive in God\'s present — which means there is a post-mortem existence that will be consummated in bodily resurrection. Christ speaks with the authority of the one who knows the Father\'s character from within — because he is the Son who dwells in the bosom of the Father (John 1:18).</p>',
    "28": '<p>A theme of Christ and the Great Commandment: a scribe who has heard the debate comes to ask which commandment is the first of all. The question is a genuine theological inquiry (unlike the tax and resurrection traps), and Christ\'s answer elevates the discussion from legal debate to covenantal heart. The scribe who asks is the one who is told he is &ldquo;not far from the kingdom&rdquo; (v.34) — his openness to the real question distinguishes him from those who approach with entrapment motives.</p>',
    "29": '<p>A direct revelation through the Shema: Jesus answers with &ldquo;Hear, O Israel: The Lord our God, the Lord is one.&rdquo; Christ\'s citation of the Shema (Deut 6:4) before the commandment identifies the love-command as covenant response to the one God. The Christological weight emerges from the NT\'s identification of Christ as the one Lord of 1 Cor 8:6 — &ldquo;to us there is one God, the Father, and one Lord, Jesus Christ.&rdquo; The Shema is expanded in the NT to include Christ within the divine identity. Christ who cites the Shema is also, in the NT\'s confession, the one Lord the Shema names.</p>',
    "30": '<p>A direct revelation of the first commandment: &ldquo;You shall love the Lord your God with all your heart and with all your soul and with all your mind and with all your strength.&rdquo; Christ cites Deut 6:5 and identifies this as the first (prōtē) commandment. In the NT, total love for God is realized in Christ: he is the one who loves the Father with his entire being — heart, soul, mind, strength — perfectly and fully, on behalf of and as the representative of those who cannot do so themselves. His life is the fulfillment of this commandment.</p>',
    "31": '<p>A direct revelation of the second commandment: &ldquo;The second is this: You shall love your neighbor as yourself. There is no other commandment greater than these.&rdquo; The citation is Lev 19:18. Christ who names this command also enacts it supremely: &ldquo;Greater love has no one than this, that someone lay down his life for his friends&rdquo; (John 15:13). The cross is the fullest expression of the neighbor-love command — he loves his neighbors unto death. The one who summarizes the law in two commandments embodies both in his life and death.</p>',
    "32": '<p>A theme of Christ commending understanding: the scribe agrees — &ldquo;Teacher, you have truly said that he is one, and there is no other besides him; and to love him with all the heart and with all the understanding and with all the strength, and to love one\'s neighbor as oneself, is much more than all whole burnt offerings and sacrifices.&rdquo; The scribe\'s summary reflects the prophetic tradition (Hos 6:6; Mic 6:6–8) that love and justice exceed ritual performance. Christ\'s commendation (v.34) shows he recognizes genuine theological understanding when it appears — not all religious inquiry is entrapment.</p>',
    "33": '<p>A theme of Christ affirming prophetic theology: love of God and neighbor exceeding sacrifices. The scribe has understood what the prophets said and what Christ embodies: the entire sacrificial system pointed toward the self-giving of Christ (Heb 10:5–10, citing Ps 40:6–8) and now that the thing pointed-at has arrived, the pointing-instruments are relativized. The scribe\'s insight is the insight Christ will confirm in the new covenant: inward transformation (love) supersedes outward performance (sacrifice).</p>',
    "34": '<p>A direct revelation: &ldquo;When Jesus saw that he answered wisely, he said to him, You are not far from the kingdom of God.&rdquo; The assessment is Christological — only the one who embodies the kingdom can judge proximity to it. To be not far is to be almost in. The scribe who understands that love exceeds sacrifice stands on the threshold of recognizing that the one who perfectly loves is the kingdom\'s King — and is therefore the one to trust. Whether the scribe crosses the threshold, Mark does not say.</p>',
    "35": '<p>A direct revelation of Christological argument: while teaching in the temple, Jesus asks, &ldquo;How can the scribes say that the Christ is the son of David?&rdquo; The question is not a denial of Davidic descent (which the Gospels affirm, e.g. 10:47–48) but a challenge to the adequacy of &ldquo;son of David&rdquo; as a complete category for the Messiah. If the Messiah is merely David\'s descendant, why does David call him &ldquo;Lord&rdquo;? The scribal Christology is too small; Christ requires a category that includes both Davidic humanity and divine lordship.</p>',
    "36": '<p>A direct citation fulfilled: &ldquo;David himself, speaking by the Holy Spirit, declared, The Lord said to my Lord, Sit at my right hand, until I put your enemies under your feet.&rdquo; The citation is Ps 110:1, the most-quoted OT text in the NT. Christ introduces it as Spirit-inspired (David speaking by the Holy Spirit), making it the authoritative word of God about the Messiah. The two &ldquo;Lords&rdquo; are YHWH (the Father) and the Adōn (the Son) — David\'s Lord is seated at YHWH\'s right hand, exercising divine authority over enemies. This is resurrection-and-ascension language applied to the Messiah before the resurrection occurs.</p>',
    "37": '<p>A direct revelation through Christological riddle: &ldquo;David himself calls him Lord. How then is he his son?&rdquo; Christ\'s question has no answer within the purely human-descendant framework. The answer is the incarnation: the Messiah is both David\'s son (human, descended from David, born of a woman) and David\'s Lord (the preexistent divine Son, with the Father before creation). The riddle requires a two-nature Christology to resolve — the doctrine the church will articulate as the eternal Son taking on human nature. The large crowd listens gladly because the question is exactly right.</p>',
    "38": '<p>A revelation of Christ\'s ethical teaching: he warns against scribes who walk in long robes and want greetings in the marketplaces. The critique targets performative religion — the use of religious identity for social status. Christ\'s own ministry inverted every status marker: he dined with sinners, touched lepers, honored children, and washed feet. His warnings about the scribes are the negative image of his own positive practice.</p>',
    "39": '<p>A theme of Christ exposing religious pride: the best seats in synagogues and places of honor at feasts. The pursuit of honor through religious role is the corruption of the very piety that should produce humility. Christ consistently reverses the honor-seeking of religious professionals — the greatest among you shall be servant of all (10:43–44). The scribes\' status-seeking is the opposite of the self-giving described in the ransom saying (10:45).</p>',
    "40": '<p>A revelation of Christ\'s condemnation of religious exploitation: &ldquo;They devour widows\' houses and for a pretense make long prayers. They will receive the greater condemnation.&rdquo; The &ldquo;greater condemnation&rdquo; reserved for those who exploit the vulnerable under religious cover is Christ\'s strongest condemnation in Mark. The widow who gives everything (vv.41–44) is immediately set against those who take everything from widows — the juxtaposition is Mark\'s sharpest moral contrast. Christ as Judge knows the difference between the two.</p>',
    "41": '<p>A revelation of Christ observing with the eyes of God: Jesus sat down opposite the treasury and watched the crowd putting money in the offering boxes. The treasury observation is the incarnate Lord watching how people relate to God with their material resources — the same Lord who will evaluate the widow\'s gift with the criterion of the heart, not the amount. Christ sees what the crowd does not see about each other and about themselves.</p>',
    "42": '<p>A revelation of Christ noticing the overlooked: a poor widow came and put in two small copper coins, which make a penny. The woman is poor, a widow (doubly vulnerable in that society), and contributes an amount too small to be noticed by the crowd. Christ notices her. This is the Christological pattern throughout Mark: he sees who is invisible to others, touches who is untouchable, calls who is uncallable. The widow who gives everything foreshadows the one who will give everything two days later.</p>',
    "43": '<p>A direct revelation: &ldquo;Truly, I say to you, this poor widow has put in more than all those who are contributing to the offering box.&rdquo; Christ\'s evaluation reverses the crowd\'s: he judges by a different calculus than the visible amount. The statement is an exercise of divine judgment — only the one who knows each heart and each circumstance can say with confidence what counts as &ldquo;more.&rdquo; The criterion is not the gift but the giver\'s relationship to what is given.</p>',
    "44": '<p>A direct revelation: &ldquo;For they all contributed out of their abundance, but she out of her poverty has put in everything she had, all she had to live on.&rdquo; The widow\'s total self-giving is the image of Christ\'s own gift: he will give not a portion of his life but all of it, and the life he gives is all he has. The widow is a type of Christ — the one who has nothing by earthly measure gives everything, and the gift is more than all the wealthy contributions combined. Mark places this scene two days before the passion (14:1): the widow\'s total self-giving and the cross are the same movement.'
  },
  "13": {
    "1": '<p>A theme of Christ and the temple: as he goes out, a disciple says, &ldquo;Look, Teacher, what wonderful stones and what wonderful buildings!&rdquo; The temple Herod had built was one of the ancient world\'s great architectural achievements — massive ashlar stones, elaborate porticoes, gleaming gold. The disciple\'s admiration is the natural response to the imposing structure. Christ\'s response (v.2) will reframe the temple entirely: its magnificence is irrelevant to what is coming, because the one speaking is the temple\'s true fulfillment (John 2:19–21).</p>',
    "2": '<p>A direct revelation: &ldquo;Do you see these great buildings? There will not be left here one stone upon another that will not be thrown down.&rdquo; Christ prophesies the temple\'s destruction with the precision that distinguishes genuine prophecy from vague prediction — specific, falsifiable, and fulfilled in 70 CE when Titus destroyed Jerusalem. The Christological significance: the temple\'s destruction is not the end of God\'s dwelling with his people but the clearing of the way for the true temple — the risen body of Christ (John 2:21) and the community that is his body (Eph 2:20–22).</p>',
    "3": '<p>A theme of private revelation: sitting on the Mount of Olives opposite the temple, Peter, James, John, and Andrew ask him privately. The inner circle who receive the private explanation of the Olivet Discourse are the same four from the first calling (1:16–20). The Mount of Olives, opposite the temple, is the site from which Zechariah prophesied the Lord\'s return (Zech 14:4) — the location itself is eschatologically loaded. Christ speaks the discourse from the vantage point of divine sovereign who sees the whole arc of history.</p>',
    "4": '<p>A theme of the disciples\' eschatological question: &ldquo;Tell us, when will these things be, and what will be the sign when all these things are about to be accomplished?&rdquo; The two-part question (when? what sign?) shapes the structure of Mark 13. Christ\'s answer gives signs but withholds the date (v.32). The withholding of the date is itself Christological: it preserves the posture of watchful dependence on God rather than calendar calculation — the appropriate response to a King who comes when he will, not when we have calculated.</p>',
    "5": '<p>A revelation of Christ warning about deception: &ldquo;See that no one leads you astray. Many will come in my name, saying, I am he! and will lead many astray.&rdquo; The warning that many will come &ldquo;in my name&rdquo; claiming to be Christ is the Christological foil that defines who Christ actually is: not one of many claimants, not the one who comes with political force and earthly armies, but the one who comes in the clouds with divine glory (v.26) — a coming that will need no announcement because its scale will be unmistakable.</p>',
    "6": '<p>A theme of false Christ claims: many will come saying &ldquo;I am he.&rdquo; The &ldquo;I am he&rdquo; (egō eimi) formula is the divine name from Exod 3:14, used by Jesus himself at the trial (14:62). False messiahs will borrow the divine-name formula; the real one will speak it before the Sanhedrin at the cost of his life. The willingness to die for the claim, rather than to use it to gain followers, is what distinguishes the genuine Christ from every imitation.</p>',
    "7": '<p>A theme of Christ relativizing earthly crises: &ldquo;When you hear of wars and rumors of wars, do not be alarmed. Such things must happen, but the end is not yet.&rdquo; The &ldquo;must happen&rdquo; (dei) is the divine necessity that governs history — Christ speaks as the sovereign Lord of history who knows its arc. The wars that terrify the nations do not threaten the outcome that God has fixed. The disciples\' call to non-alarm is grounded in the identity of the one who is speaking: the Judge of all the earth knows how it ends.</p>',
    "8": '<p>A theme of the birth pangs: nation will rise against nation, there will be earthquakes and famines — these are the beginning of the birth pangs. The metaphor of birth pangs (archē ōdinōn — the same phrase the rabbis used for the &ldquo;birth pangs of the Messiah&rdquo;, chevlei hamashiach) positions the sufferings as the labor before new creation, not the death of history. Christ is the midwife of the new age: the pain is real but what is being born is the kingdom. Every war and earthquake is a contraction, not the end.</p>',
    "9": '<p>A direct revelation of Christ sending his followers as witnesses: &ldquo;They will deliver you over to councils and you will be beaten in synagogues, and you will stand before governors and kings for my sake, to bear witness before them.&rdquo; The disciples\' suffering for Christ\'s sake is a continuation of his own being delivered over (paradidōmi, 9:31; 10:33; 14:41). Christ sends his followers into a passion-shaped mission — the testimony given before authorities in the disciples\' sufferings extends the testimony he gave before the Sanhedrin and Pilate.</p>',
    "10": '<p>A direct revelation of the universal mission: &ldquo;And the gospel must first be preached to all nations.&rdquo; The universal scope of the gospel\'s reach is given as the necessary precondition before the end. Christ\'s mission does not end at Israel\'s borders — it extends to all nations (panta ta ethnē), fulfilling the covenant promise to Abraham (Gen 12:3) and the Isaianic vision of light to the Gentiles (Isa 49:6). The one who declared all foods clean (7:19) and fed Gentile crowds (8:1–9) now explicitly names the worldwide proclamation as the mission\'s scope.</p>',
    "11": '<p>A direct revelation of the Holy Spirit speaking through believers: &ldquo;When they bring you to trial and deliver you over, do not be anxious beforehand what you are to say, but say whatever is given you in that moment, for it is not you who speak, but the Holy Spirit.&rdquo; Christ promises the Spirit\'s presence in the disciples\' testimony — the same Spirit who descended at his baptism (1:10) and who will be given after his resurrection (John 20:22). The disciples who testify before kings are speaking as Christ spoke before Pilate, sustained by the same Spirit.</p>',
    "12": '<p>A theme of family betrayal in the cross-shaped community: brother will deliver brother over to death and the father his child. The persecution Christ anticipates reaches into the most intimate bonds — the same bonds that following him required leaving (1:18–20; 10:29–30). The community of disciples is not insulated from suffering; it is the community that follows the Crucified, and the cross-shape extends to family rupture. The cost of following Christ is counted in relational as well as physical currency.</p>',
    "13": '<p>A direct revelation: &ldquo;You will be hated by all for my name\'s sake. But the one who endures to the end will be saved.&rdquo; The hatred &ldquo;for my name\'s sake&rdquo; is the hatred that the world directs at Christ deflected onto his followers. The endurance to the end (hypomeinas eis telos) is the posture of the cross: Christ himself endured to the end (15:37), and his followers share that endurance as the form of their participation in his death and resurrection. Salvation belongs to those who do not abandon the cross-shaped path.</p>',
    "14": '<p>A direct revelation applying Daniel\'s prophecy: &ldquo;When you see the abomination of desolation standing where it ought not — let the reader understand — then let those who are in Judea flee to the mountains.&rdquo; Christ applies Dan 9:27; 11:31; 12:11 to a coming sacrilege in Jerusalem — which was fulfilled in 70 CE when Roman standards (with their imperial images) entered the temple, and previously prefigured by Antiochus IV\'s 167 BCE desecration. The parenthetical &ldquo;let the reader understand&rdquo; signals that this is a coded reference requiring interpretive attention, as Daniel\'s original vision required.</p>',
    "15": '<p>A theme of urgent flight: &ldquo;Let the one who is on the housetop not go down, nor enter his house, to take anything out.&rdquo; The urgency of the escape instruction signals that the coming judgment will not wait for preparation. Christ\'s pastoral concern for his followers\' physical survival is expressed in practical detail — no time to retrieve possessions. The same Lord who provides bread in the wilderness (6:41; 8:6) gives escape instructions for the coming catastrophe, because he knows precisely what is coming and when.</p>',
    "16": '<p>A theme of Christ\'s care for the vulnerable: &ldquo;And let the one who is in the field not turn back to take his cloak.&rdquo; The practical instruction (leave your cloak behind) is a small pastoral detail that reveals Christ\'s concern for individual survival in a collective catastrophe. The worker in the field who has removed his cloak for labor is to flee immediately — survival over property. This is the Lord who noticed the widow\'s two coins (12:42) also noticing the worker in the field who would lose his cloak.</p>',
    "17": '<p>A revelation of Christ\'s compassion in judgment: &ldquo;And alas for women who are pregnant and for those who are nursing infants in those days!&rdquo; The compassionate exclamation (ouai — woe, not condemnation but grief) for the most vulnerable shows that Christ\'s eschatological instruction is not emotionally detached. He grieves the suffering that the judgment will bring on the innocent and the physically constrained. The judge who will come in glory is the same one who showed compassion for the crowds who had nothing to eat (8:2).</p>',
    "18": '<p>A revelation of Christ teaching prayer in connection with judgment: &ldquo;Pray that it may not happen in winter.&rdquo; Christ instructs prayer that the flight not occur in winter — when escape would be most difficult, fields would provide no food, and roads would be impassable. The instruction to pray about specific practical circumstances grounds eschatological vigilance in present intercession. The Lord who knows when these things will happen calls his followers to pray over the details, not merely the outcome — prayer is the appropriate response to his sovereign foreknowledge.</p>',
    "19": '<p>A direct revelation of the tribulation\'s severity: &ldquo;For in those days there will be such tribulation as has not been from the beginning of the creation that God created until now, and never will be.&rdquo; The superlative suffering surpassing all previous history echoes Dan 12:1 (&ldquo;a time of trouble such as never has been&rdquo;). Christ speaks with the authority of the creator of history — he knows the full range of human suffering because he is both its witness and, at the cross, its bearer. The unmatched severity of the coming tribulation makes the following mercy (v.20) the more remarkable.</p>',
    "20": '<p>A direct revelation of divine mercy cutting short judgment: &ldquo;And if the Lord had not cut short the days, no human being would be saved. But for the sake of the elect, whom he chose, he shortened the days.&rdquo; The shortening of the tribulation for the sake of the elect is an act of covenant mercy — God\'s commitment to his people constrains even the scope of judgment. Christ who speaks this is the one through whom the election comes (Eph 1:4 — chosen in him) and who himself is the ground of the covenant mercy that shapes history.</p>',
    "21": '<p>A theme of Christ as the standard against which false claims are measured: &ldquo;And then if anyone says to you, Look, here is the Christ! or Look, there he is! do not believe it.&rdquo; The false-christ warning (repeated from v.6) gains force here: in the tribulation\'s desperation, false messiahs will find willing audiences. Christ warns that his return will be unmistakable — not a local sighting or a rumor (v.26 — the whole earth will see the Son of Man). Any Christ who can be pointed to in a specific location is not the Christ who comes in clouds of glory.</p>',
    "22": '<p>A revelation of Christ distinguishing himself from false prophets: false christs and false prophets will arise and perform signs and wonders, to lead astray, if possible, the elect. The possibility of miraculous signs performed by impostors — and the elect being immune to their deception — is a Christological statement about the nature of the elect\'s bond with Christ. Those who know the Shepherd\'s voice (John 10:27) will not follow strangers (John 10:5) regardless of their signs. The ability of the false to produce signs does not make them true; only the resurrection-confirmed Son of God is the true Christ.</p>',
    "23": '<p>A direct revelation: &ldquo;But be on guard; I have told you all things beforehand.&rdquo; The forewarning is itself a Christological claim: only the one who knows history in advance can give a complete warning before the events occur. The &ldquo;all things told beforehand&rdquo; echoes the prophetic tradition (Amos 3:7 — the Lord does nothing without revealing it to his servants) and positions Christ as the prophet greater than all prophets — the one whose foreknowledge is divine because he is divine.</p>',
    "24": '<p>A revelation of cosmic-sign language from the prophets: &ldquo;In those days, after that tribulation, the sun will be darkened and the moon will not give its light.&rdquo; The solar and lunar darkening language is drawn from the prophetic tradition\'s imagery for divine judgment — Isa 13:10 (against Babylon), Joel 2:10 (the day of the Lord), Amos 8:9. In the prophetic idiom, such language signals the collapse of the existing political and social order under divine judgment. Christ borrows the full arsenal of prophetic judgment-language for the end-time event he is announcing.</p>',
    "25": '<p>A revelation of cosmic shaking at Christ\'s coming: &ldquo;The stars will be falling from heaven, and the powers in the heavens will be shaken.&rdquo; The heavenly powers shaking echoes Isa 34:4 (judgment on Edom extended to the cosmos) and Hag 2:6 (the Lord shaking heavens and earth at the new temple\'s establishment). The cosmic shaking at the Son of Man\'s coming is the creation\'s response to its Lord\'s return — the same creation that was subjected to futility (Rom 8:20) trembles at the coming liberation. The heavenly powers that have opposed God\'s people will have their authority removed.</p>',
    "26": '<p>A direct revelation: &ldquo;And then they will see the Son of Man coming in clouds with great power and glory.&rdquo; The citation is Dan 7:13 — the one like a son of man coming to the Ancient of Days to receive universal dominion. Christ applies this text to his own return, as he applied it at the trial (14:62). The coming in clouds is divine-presence language throughout the OT (Exod 19:16; Ps 104:3; Isa 19:1); the one who comes in clouds is the one who dwells in clouds — the Lord himself. Christ identifies his parousia as the arrival of the divine Judge who receives eternal dominion over all kingdoms.</p>',
    "27": '<p>A direct revelation of the eschatological gathering: &ldquo;And then he will send out the angels and gather his elect from the four winds, from the ends of the earth to the ends of heaven.&rdquo; The gathering of the elect by the Son of Man\'s angels echoes Deut 30:4 (the Lord gathering his scattered people) and Isa 11:12 (God gathering the dispersed of Israel from the four corners). Christ identifies his elect as the new-covenant people gathered at his return — the community whose eschatological identity is shaped by the one who will gather them. The mission to &ldquo;all nations&rdquo; (v.10) produces the elect who will be gathered from among all nations.</p>',
    "28": '<p>A theme of Christ as teacher of eschatological signs: the fig tree parable — when the branch becomes tender and puts out leaves, you know that summer is near. Christ draws on natural seasonal signs to establish the principle that the signs preceding his coming are readable. The cosmic signs (vv.24–25) function like the fig tree\'s budding: they signal that the time is near. The one who reads the fig tree teaches his followers to read the signs of his own coming with the same attentiveness.</p>',
    "29": '<p>A theme of nearness: &ldquo;When you see these things taking place, you know that he is near, at the very gates.&rdquo; The nearness of the Son of Man when the signs appear is the theological structure of advent watchfulness: the signs do not announce that the end is distant but that it is imminent. The one at the gates is Christ the returning Lord — the same Lord who entered Jerusalem through gates (11:1–10), who will re-enter history through the gates of the cosmos at his parousia.</p>',
    "30": '<p>A direct revelation: &ldquo;Truly, I say to you, this generation will not pass away until all these things take place.&rdquo; The &ldquo;this generation&rdquo; refers to the contemporaries of Jesus who will see the fulfillment of the near-term signs — the tribulation, the abomination, the destruction of Jerusalem — in 70 CE. Christ speaks with prophetic precision: the near-term fulfillment (70 CE) happened within one generation of his ministry. The distant fulfillment (the parousia) he has refused to date (v.32), preserving the posture of watchfulness.</p>',
    "31": '<p>A direct revelation: &ldquo;Heaven and earth will pass away, but my words will not pass away.&rdquo; The permanence of Christ\'s words is the permanence of divine speech. The creation that &ldquo;passes away&rdquo; is the same creation spoken into existence by God\'s word (Gen 1; John 1:3). The one whose word created heaven and earth now speaks a word that outlasts creation. The authority behind this statement is the authority of the divine Son — no human teacher could make this claim honestly. His words are the words of the eternal God expressed through the incarnate Son.</p>',
    "32": '<p>A direct revelation of the Son\'s genuine limitation in his incarnation: &ldquo;But about that day or that hour no one knows, not even the angels in heaven, nor the Son, but only the Father.&rdquo; The Son\'s genuine not-knowing of the day and hour is a statement about the kenōsis of the incarnation (Phil 2:7 — he emptied himself). The eternal Son who knows all things has, in his incarnation, taken on a genuine human mode of existence in which this specific knowledge is not available to his human consciousness. This is the NT\'s clearest statement of the two-nature reality: the same person whose words outlast heaven and earth genuinely does not know the date of his own return in his human nature.</p>',
    "33": '<p>A direct revelation: &ldquo;Be on guard, keep awake. For you do not know when the time will come.&rdquo; The call to watchfulness is grounded in the hidden date — not-knowing creates the posture of perpetual readiness. Christ the returning master calls his servants to vigilance not as anxiety but as faith: the one who comes is coming, the question is only when. The community that lives in light of the parousia is the community that embodies this vigilance — the marks of Christ in the world include readiness for his return.</p>',
    "34": '<p>A revelation of Christ as the master who gives authority and leaves: &ldquo;It is like a man going on a journey, when he leaves home and puts his servants in charge, each with his work, and commands the doorkeeper to stay awake.&rdquo; The parable is a Christological self-portrait: Christ is the master who has gone away (the ascension), who has distributed responsibilities to his servants (the church\'s mission), and who will return at an unexpected hour. The doorkeeper commanded to stay awake is the whole church — watchfulness is the form of faithful service during the master\'s absence.</p>',
    "35": '<p>A direct revelation: &ldquo;Therefore stay awake — for you do not know when the master of the house will come, in the evening, or at midnight, or when the rooster crows, or in the morning.&rdquo; The four Roman night watches that Christ names (evening, midnight, cockcrow, morning) are the watches of the passion night — the time frame of his own arrest, trial, and crucifixion. The master whose return is being awaited is the master who first went through the night of suffering. The watches that frame the passion (14:17, 14:72, 15:1) are the watches that frame the disciples\' expectation. Watchfulness for the returning Lord is inseparable from remembering the cross.</p>',
    "36": '<p>A theme of Christ calling to faithful service: &ldquo;Lest he come suddenly and find you asleep.&rdquo; The servant found asleep has abandoned the posture of expectancy — no longer living as one who awaits the master\'s return. The sleep that Christ warns against is not physical but spiritual: the relaxation of the eschatological tension, the settling into the present age as if the master is not coming. Christ calls his community to live in the between-time (ascension and parousia) with the alertness that his imminent return demands.</p>',
    "37": '<p>A direct revelation: &ldquo;And what I say to you I say to all: Stay awake.&rdquo; The final word of the Olivet Discourse is a command addressed beyond the inner circle to the whole church in every generation. The command to stay awake is the practical form of belief in the parousia: the one who believes the master is coming lives differently from one who has concluded he is delayed indefinitely. Christ speaks the command to Mark\'s persecuted Roman community (ca. 65–70 CE) and through Mark to all subsequent readers — the call to watchfulness is the permanent posture of the community that awaits its Lord.'
  }
}

def main():
    existing = load_comm('mkt-christ', 'mark')
    merge_comm(existing, MARK_CH12_13)
    save_comm('mkt-christ', 'mark', existing)
    ch12 = len(existing.get('12', {}))
    ch13 = len(existing.get('13', {}))
    print(f'Mark 12: {ch12} verses, Mark 13: {ch13} verses.')

if __name__ == '__main__':
    main()
